Future<http.Response> logHttpRequest(http.Request request) async {
  final stopwatch = Stopwatch()..start();
  
  ProductionLogger.logHttp(
    'REQUEST',
    request.url.toString(),
    request.headers,
    request.body,
  );
  
  try {
    final response = await request.send();
    stopwatch.stop();
    
    ProductionLogger.logHttp(
      'RESPONSE',
      request.url.toString(),
      response.headers,
      null,
      response.statusCode,
      stopwatch.elapsed,
    );
    
    return response;
  } catch (e) {
    stopwatch.stop();
    ProductionLogger.logError('HTTP Error: $e');
    rethrow;
  }
}

